{
  "verses": [
    {
      "n": 10,
      "column": "left",
      "text": "Weens Meistertis pataifa\nwiſtas Leetas pareiſi/ bet kas\nkahdu Gekki fader/ tas fader Mai-\ntataju.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Kà Suns fawu Weh-\nmekli atkaž eerihj/ ta patt dſen\ntas Gekkis atkat fawu Gekkibu.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Kad tu kahdu Wihru re-\ndſi/ kas pats par Gudru tur-\nrahs/ tad warr no weena Getka\nwairak zerrecht/ neka no tahda.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Tas Slinkis fakka:\nWeens jauns Lauwa irr us Zek-\ntu/ weens Lauwa irr us Eelahm.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Kà Durwis grohsahs\neekſch fawahm Engehin/ ta patt\ntas Slinkis us fawu Gultu.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Tas Slinkis paſlepj fa-\nwu Rohku Asoti/ un gruhti tam\nnahkahs to atkaž pee Muttes\nkitt.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Tas Slinkis ſchkeetahs\nfawà Prahta gudraks neka ſep-\ntixi/ kas gudrus Padohmus\nmahza.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Kas tezzen eedams ſwe-\nfchà Kilda eejauxahs/ tas irr itt\nta kas weenu Sunnt pee Aufim\nkarrina.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Itt ka weens/ kas pats\npar traktu darrahs/ ar Lahpahm\nBultahm un nahwigahm Brux-\nrahm fchauj/\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Ta patt irr tas Wihrs/\nkas fatvu Tuivaku peewit/ un\nfakka: Es to tikcai par Smeekſi\nDarriju.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Kad Mallas newaid/ tad\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "isdferft tas Ugguns/ un kad ta\nAprunnatajs nohſt irr/ tad mi\ntejahs ta Kilda.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Itt ka no iſdsiffischab\nOhglehm twehlainas Ohgie\ntohp/ un ka no Malkas Uggur\nzelfkahs/ ta patt pazelt weer\nRehjejs Zilweks Kiidu.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Ta Aprunnataja Wahri\nirr itt ka Sitteni/ un eet zaſ\nSirdi.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Mihſta Mutte un niſu\nSirds/ irr ka Pohda Gabbals a\nSudraba Puttehm pahrwilkte\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Tas Genaidneeks tohp a-\nſhts pee tawas Wallodas/ jep\nſchu wiſch fawa Sirdsdibbin\nto Wiltibu dſeu.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Kad wiſch mihſi runna\ntad ne tizzi winnam/ jo fepti\nnas Negantibas irr wina\nSirdi.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Kas fleppent Naidu tur-\nka tas peewit/ ta patcha Bleh-\ndiba taps preekſch Laudim fin-\nnama.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Kas Bedrf rohf/ tas krit-\ntihs eekſch tahs/ un kas Akmin-\nwaltſa/ us to tas atwelfees.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Wiltiga Mehle eenihd te-\nkas winnu pahrmahza/ un wee-\nna mihſta Mutte padarra Boh-\njà-Eefchann.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
